import Vue from "vue";
import VueRouter from "vue-router";

Vue.use(VueRouter)

import errorPage from './view/errorPage.vue'
import test from './view/test.vue'
import blogList from './view/blogList.vue'
import blogPage from './view/blogPage.vue'
import edit from './view/edit.vue'
import register from './view/register.vue'
import registerEmail from './view/registerEmail.vue'
import login from './view/login.vue'
import user from './view/user.vue'

const routes = [
    {
        path: '*',
        component: errorPage,
        meta: {
            title: '404 没有找到这个页面'
        },
    },
    {
        path: '/test',
        component: test,
        meta: {
            title: '测试页面'
        },
    },
    {
        path: '/',
        component: blogList,
        meta: {
            title: 'Qisato Blog'
        },
    },
    {
        path: '/blog',
        component: blogList,
        meta: {
            title: 'Qisato Blog'
        },
    },
    {
        path: '/blog/page/:id',
        component: blogPage,
        meta: {
            title: 'Blog文章'
        },
        props: true
    }, {
        path: '/blog/edit',
        component: edit,
        meta: {
            title: '文章编辑器'
        },
    }, {
        path: '/blog/edit/:id',
        component: edit,
        meta: {
            title: '文章编辑器',
        },
        props: true
    }, {
        path: '/register',
        component: register,
        meta: {
            title: '新用户注册'
        },
    }, {
        path: '/register/email',
        component: registerEmail,
        meta: {
            title: '邮件申请注册'
        },
    }, {
        path: '/login',
        component: login,
        meta: {
            title: '登录'
        },
    }, {
        path: '/user/:id',
        component: user,
        meta: {
            title: '用户'
        },
        props: true
    }
]

const router = new VueRouter({
    routes,
    mode: 'history'
})

export default router