<template>
  <div>
    <canvas @click="loadCanvas" id="canvas">
      您的浏览器不支持 HTML5 canvas 标签。
    </canvas>
    <div @click="loadCanvas" style="font-size: 12px; cursor: pointer">
      看不清，换一张
    </div>
  </div>
</template>
<script>
export default {
  name: "vcode",
  data: () => {
    return {
      canvas: null,
      ctx: null,
      det: null,
      try: 0,
    };
  },
  props: ["type"],
  mounted() {
    this.loadCanvas();
  },
  methods: {
    loadCanvas() {
      this.initCanvas();
      this.tip();
      console.log(this.type);
      if (this.type == 3) {
        this.thirdOrderDeterminant(10);
      } else if (this.type == 4) {
        this.fourthOrderDeterminant(10);
      }
    },
    initCanvas() {
      this.canvas = document.getElementById("canvas");
      this.canvas.width = "300";
      this.canvas.height = "200";
      this.ctx = this.canvas.getContext("2d");
      this.ctx.fillStyle = "#ffffff";
      this.ctx.fillRect(0, 0, 300, 200);
    },
    thirdOrderDeterminant(max) {
      let ctx = this.ctx;
      ctx.fillStyle = "#000000aa";
      ctx.moveTo(70, 30);
      ctx.lineTo(70, 170);
      ctx.moveTo(230, 30);
      ctx.lineTo(230, 170);
      ctx.stroke();
      ctx.font = "300 36px serif";
      ctx.textAlign = "center";
      this.det = [
        [this.creatRandom(max), this.creatRandom(max), this.creatRandom(max)],
        [this.creatRandom(max), this.creatRandom(max), this.creatRandom(max)],
        [this.creatRandom(max), this.creatRandom(max), this.creatRandom(max)],
      ];
      for (let i = 0; i < this.det.length; i++) {
        for (let j = 0; j < this.det[i].length; j++) {
          ctx.fillText(this.det[i][j], 110 + i * 40, 75 + j * 40);
        }
      }
    },
    fourthOrderDeterminant(max) {
      let ctx = this.ctx;
      ctx.fillStyle = "#000000";
      ctx.moveTo(50, 20);
      ctx.lineTo(50, 180);
      ctx.moveTo(250, 20);
      ctx.lineTo(250, 180);
      ctx.stroke();
      ctx.font = "300 28px serif";
      ctx.textAlign = "center";
      this.det = [
        [
          this.creatRandom(max),
          this.creatRandom(max),
          this.creatRandom(max),
          this.creatRandom(max),
        ],
        [
          this.creatRandom(max),
          this.creatRandom(max),
          this.creatRandom(max),
          this.creatRandom(max),
        ],
        [
          this.creatRandom(max),
          this.creatRandom(max),
          this.creatRandom(max),
          this.creatRandom(max),
        ],
        [
          this.creatRandom(max),
          this.creatRandom(max),
          this.creatRandom(max),
          this.creatRandom(max),
        ],
      ];
      for (let i = 0; i < this.det.length; i++) {
        for (let j = 0; j < this.det[i].length; j++) {
          ctx.fillText(this.det[i][j], 90 + i * 40, 50 + j * 40);
        }
      }
    },
    tip() {
      let ctx = this.ctx;
      ctx.fillStyle = "#000000";
      ctx.font = "300 9px monospace";
      ctx.textAlign = "left";
      ctx.fillText("Creation Time: " + this.getDate(), 5, 10);
      ctx.textAlign = "right";
      ctx.fillText("©2019-2021 MaoerXiachuan", 295, 195);
      //噪点
      for (let i = 0; i < 6000; i++) {
        let x = this.creatRandom(300),
          y = this.creatRandom(200);
        let color = this.creatRandom(0xffffff).toString(16);
        for (let c = color.length; c < 6; c++) {
          color = "0" + color;
        }
        ctx.fillStyle = "#" + color;
        ctx.fillRect(x, y, 1, 1);
      }
      //logo
      let logo = new Image();
      logo.src = require("@/img/logo.png");
      logo.onload = () => {
        ctx.globalAlpha = 0.2;
        ctx.drawImage(logo, 65, 15, 170, 175);
      };
    },
    creatRandom(v) {
      return Math.floor(Math.random() * v);
    },
    getDate() {
      let d = new Date();
      return (
        d.getFullYear() +
        "-" +
        (d.getMonth() + 1) +
        "-" +
        d.getDate() +
        " " +
        d.getHours() +
        ":" +
        (d.getMinutes() < 10 ? "0" + d.getMinutes() : d.getMinutes()) +
        ":" +
        (d.getSeconds() < 10 ? "0" + d.getSeconds() : d.getSeconds())
      );
    },
    verifyVcode(value) {
      if (value == this.solutionDeterminant(this.det)) {
        return true;
      } else {
        if (this.try < 2) {
          this.try++;
        } else {
          this.try = 0;
          this.loadCanvas();
        }
        console.log(this.try);
        return false;
      }
    },
    solutionDeterminant(d) {
      let r = 0;
      if (d.length == 3) {
        r =
          d[0][0] * d[1][1] * d[2][2] +
          d[1][0] * d[2][1] * d[0][2] +
          d[2][0] * d[0][1] * d[1][2] -
          d[0][2] * d[1][1] * d[2][0] -
          d[1][2] * d[2][1] * d[0][0] -
          d[2][2] * d[0][1] * d[1][0];
      } else if (d.length == 4) {
        r =
          (d[0][0] * d[1][1] - d[0][1] * d[1][0]) *
            (d[2][2] * d[3][3] - d[2][3] * d[3][2]) -
          (d[0][0] * d[1][2] - d[0][2] * d[1][0]) *
            (d[2][1] * d[3][3] - d[2][3] * d[3][1]) +
          (d[0][0] * d[1][3] - d[0][3] * d[1][0]) *
            (d[2][1] * d[3][2] - d[2][2] * d[3][1]) +
          (d[0][1] * d[1][2] - d[0][2] * d[1][1]) *
            (d[2][0] * d[3][3] - d[2][3] * d[3][0]) -
          (d[0][1] * d[1][3] - d[0][3] * d[1][1]) *
            (d[2][0] * d[3][2] - d[2][2] * d[3][0]) +
          (d[0][2] * d[1][3] - d[0][3] * d[1][2]) *
            (d[2][0] * d[3][1] - d[2][1] * d[3][0]);
      }
      return r;
    },
  },
};
</script>
<style scoped>
#canvas {
  width: 100%;
  height: 100%;
  cursor: pointer;
}
</style>