<template>
  <div>
    <el-dialog
      :visible.sync="dialog"
      :show-close="false"
      :modal="false"
      width="500px"
      :append-to-body="true"
      top="30vh"
      class="blur"
      :custom-class="theme.blur ? 'blur' : null"
      style="background-color: #0000 !important"
      :close-on-click-modal="false"
    >
      <div style="text-align: center; font-size: 22px; margin-top: -25px">
        您已登录,正在跳转到首页
      </div>
    </el-dialog>
  </div>
</template>
<script>
import { getCookie } from "@/api/function";
export default {
  name: "test",
  data: () => {
    return {
      dialog: false,
    };
  },
  props: ["theme"],
  created() {
    if (getCookie("user") && getCookie("cookie")) {
      (this.dialog = true),
        setTimeout(() => {
          window.location = "/blog";
        }, 2000);
    } else {
      this.$emit("login", false);
    }
  },
};
</script>
