<template>
  <div id="blog">
    <el-container>
      <el-main style="padding: 80px 0 0 0">
        <div class="pagePanel" :class="{ blur: theme.blur }">
          <el-skeleton
            :rows="8"
            :loading="loading"
            animated
            style="opacity: 0.8"
          />
          <div
            style="position: absolute; top: 16px; right: 10px; font-size: 16px"
            v-if="format"
          >
            <span style="color: #696969">
              <span style="cursor: pointer" @click="pageCollect"
                ><i
                  :class="collect ? 'fas fa-star' : 'far fa-star'"
                  :style="{ color: collect ? '#FFB300' : 'inherit' }"
                ></i>
              </span>
              &nbsp;&nbsp;
              <el-popover
                trigger="hover"
                :popper-class="theme.blur ? 'blur' : null"
                ><span style="cursor: pointer" slot="reference"
                  ><i class="fas fa-paper-plane"></i
                ></span>
                <div
                  style="color: #696969; font-size: 20px; text-align: center"
                >
                  <div style="padding: 6px 12px">
                    <a :href="share.qq" target="_blank">
                      <i class="fab fa-qq"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.qzone" target="_blank">
                      <i class="fab fa-qq"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.wechat" target="_blank">
                      <i class="fab fa-weixin"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.weibo" target="_blank">
                      <i class="fab fa-weibo"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.twitter" target="_blank">
                      <i class="fab fa-twitter"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.facebook" target="_blank">
                      <i class="fab fa-facebook"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.linkedin" target="_blank">
                      <i class="fab fa-linkedin-in"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.skype" target="_blank">
                      <i class="fab fa-skype"></i>
                    </a>
                  </div>
                  <el-input
                    size="mini"
                    :value="url"
                    style="margin-bottom: 10px"
                  >
                    <template slot="prepend">本文链接</template>
                    <el-button slot="append" @click="copyText(url)"
                      ><i class="fas fa-copy fa-fw"></i>复制</el-button
                    >
                  </el-input>
                </div>
              </el-popover>
              &nbsp;&nbsp;
              <span style="cursor: pointer"
                ><i class="fas fa-exclamation-triangle"></i
              ></span>
              &nbsp;&nbsp;
            </span>
          </div>
          <div class="pageText" v-html="format"></div>
          <div style="text-align: right" v-if="format">
            <span style="color: #696969">
              <span style="cursor: pointer" @click="pageCollect"
                ><i
                  :class="collect ? 'fas fa-star' : 'far fa-star'"
                  :style="{ color: collect ? '#FFB300' : 'inherit' }"
                ></i>
                {{ collect ? "已收藏" : "收藏" }}
              </span>
              &nbsp;
              <el-popover
                trigger="hover"
                :popper-class="theme.blur ? 'blur' : null"
              >
                <span style="cursor: pointer" slot="reference"
                  ><i class="fas fa-paper-plane"></i> 分享</span
                >
                <div
                  style="color: #696969; font-size: 20px; text-align: center"
                >
                  <div style="padding: 6px 12px">
                    <a :href="share.qq" target="_blank">
                      <i class="fab fa-qq"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.qzone" target="_blank">
                      <i class="fab fa-qq"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.wechat" target="_blank">
                      <i class="fab fa-weixin"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.weibo" target="_blank">
                      <i class="fab fa-weibo"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.twitter" target="_blank">
                      <i class="fab fa-twitter"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.facebook" target="_blank">
                      <i class="fab fa-facebook"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.linkedin" target="_blank">
                      <i class="fab fa-linkedin-in"></i>
                    </a>
                    &nbsp;&nbsp;
                    <a :href="share.skype" target="_blank">
                      <i class="fab fa-skype"></i>
                    </a>
                  </div>
                  <el-input
                    size="mini"
                    :value="url"
                    style="margin-bottom: 10px"
                  >
                    <template slot="prepend">本文链接</template>
                    <el-button slot="append" @click="copyText(url)"
                      ><i class="fas fa-copy fa-fw"></i>复制</el-button
                    >
                  </el-input>
                </div>
              </el-popover>
              &nbsp;
              <span style="cursor: pointer"
                ><i class="fas fa-exclamation-triangle"></i>举报</span
              >
            </span>
            <span v-if="pageSelf" :style="{ color: this.theme.color }">
              &nbsp;
              <a :href="editPath" target="_blank">编辑文章</a>
              &nbsp;
              <span
                style="color: #f4511e; cursor: pointer"
                @click="delPageDialog = true"
                >删除文章</span
              >
            </span>
          </div>
        </div>
      </el-main>
      <el-aside class="hidden-xs-only" width="274px">
        <side-bar
          :user="user"
          :theme="theme"
          :menu="pageSelf ? menuA : menuB"
          :login="login"
          :starButton="!pageSelf"
          ref="sideBar"
        />
      </el-aside>
    </el-container>
    <div>
      <el-dialog
        :modal="false"
        title="验证码验证"
        :visible.sync="vcodeDialog"
        :append-to-body="true"
        :close-on-click-modal="false"
        :close-on-press-escape="false"
        :show-close="false"
        :custom-class="theme.blur ? 'blur' : null"
        class="blur"
        style="user-select: none; background-color: #0000 !important"
      >
        <div>请计算下列问题并输入运算结果</div>
        <vcode
          type="3"
          ref="vcode"
          style="
            width: 300px;
            height: 200px;
            margin: 20px auto;
            border: #909090 2px dashed;
          "
        />
        <el-input
          style="margin: 20px 0"
          v-model="vcodeInput"
          :clearable="true"
          size="small"
        />
        <div style="text-align: right">
          <el-button size="small" type="primary" @click="verifyVcode"
            >验证</el-button
          >
        </div>
        <div></div>
      </el-dialog>
      <el-dialog
        top="20vh"
        width="500px"
        :modal="false"
        title="删除文章"
        :visible.sync="delPageDialog"
        :append-to-body="true"
        :custom-class="theme.blur ? 'blur' : null"
        class="blur"
        style="background-color: #0000 !important"
      >
        <div style="font-size: 16px">
          <div style="padding: 0 20px">
            <i class="el-icon-warning" style="color: #f56c6c"></i>
            您真的要删除这篇文章吗？<br />
            &nbsp;&nbsp;&nbsp;&nbsp;此操作会让这篇文章永远在本站消失<br />
          </div>
          <div
            style="
              text-align: center;
              font-size: 20px;
              padding: 14px;
              margin: 14px 0;
              border: #909090 2px dashed;
              font-family: Consolas, 'Ubuntu Mono', monospace;
            "
          >
            {{ id }}
          </div>
          <div>
            <el-input
              v-model="delnoid"
              placeholder="输入文章的noid以执行该操作"
            />
          </div>
          <div style="text-align: right; margin-top: 20px">
            <el-button @click="delPageDialog = false">取消</el-button>
            <el-button type="danger" @click="delPage">确认删除</el-button>
          </div>
        </div>
      </el-dialog>
    </div>
  </div>
</template>
<script>
import showdown from "showdown";
import Prism from "prismjs";
import "@/css/prism.css";
import sideBar from "./components/sideBar.vue";
import vcode from "./components/vcode.vue";
import {
  getBlogPage,
  getBlogData,
  getUserData,
  checkLoginState,
  delPage,
  checkCollect,
  pageCollect,
} from "@/api/ajax.js";
import { getCookie, sha256 } from "@/api/function.js";

export default {
  name: "page",
  components: {
    sideBar,
    vcode,
  },
  data: function () {
    return {
      url: null,
      loading: true,
      md: "",
      format: "",
      vcodeDialog: false,
      vcodeInput: null,
      blogData: {},
      user: {},
      pageSelf: false,
      editPath: null,
      delPageDialog: false,
      delnoid: null,
      collect: false,
      share: {
        qq: null,
        qzone: null,
        wechat: null,
        weibo: null,
        twitter: null,
        facebook: null,
        linkedin: null,
        skype: null,
      },
      menuA: {
        userActionMenuPanel: [
          //建议：分两组，每组两个
          {
            group: "0",
            list: [
              {
                title: "写文章",
                path: "/blog/edit",
                icon: "fas fa-edit",
              },
              {
                title: "传照片",
                path: "",
                icon: "fas fa-image",
              },
            ],
          },
          {
            group: "1",
            list: [
              {
                title: "个人主页",
                path: "",
                icon: "fas fa-user",
              },
              {
                title: "创作中心",
                path: "",
                icon: "fas fa-paper-plane",
              },
            ],
          },
        ],
        userActionMenuList: [
          {
            title: "我的收藏",
            path: "",
            icon: "fas fa-bookmark fa-fw",
          },
          {
            title: "我的关注",
            path: "",
            icon: "fas fa-star fa-fw",
          },
          {
            title: "我的相册",
            path: "",
            icon: "fas fa-images fa-fw",
          },
          {
            title: "个人资料",
            path: "",
            icon: "fas fa-child fa-fw",
          },
        ],
      },
      menuB: {
        userActionMenuPanel: [
          //建议：分两组，每组两个
          {
            group: "0",
            list: [
              {
                title: "ta的文章",
                path: "",
                icon: "fas fa-file-alt",
              },
              {
                title: "ta的照片",
                path: "",
                icon: "fas fa-images",
              },
            ],
          },
          {
            group: "1",
            list: [
              {
                title: "ta的主页",
                path: "",
                icon: "fas fa-user",
              },
              {
                title: "创作中心",
                path: "",
                icon: "fas fa-paper-plane",
              },
            ],
          },
        ],
        userActionMenuList: [
          {
            title: "ta的收藏",
            path: "",
            icon: "fas fa-bookmark fa-fw",
          },
          {
            title: "ta的关注",
            path: "",
            icon: "fas fa-star fa-fw",
          },
          {
            title: "ta的资料",
            path: "",
            icon: "fas fa-child fa-fw",
          },
        ],
      },
    };
  },
  props: ["id", "theme", "login"],
  created() {
    this.getBlogData();
  },
  methods: {
    //获取文章内容
    getContent() {
      getBlogPage(this.id, (returns) => {
        if (returns.code == "200") {
          this.md = returns.data;
          this.format = this.markdown(this.md);
          this.loading = false;
          this.$nextTick(() => {
            for (
              var i = 0;
              i < document.getElementsByTagName("pre").length;
              i++
            ) {
              document.getElementsByTagName("pre")[i].className =
                "language-js line-numbers";
            }
            Prism.highlightAll();
          });
          document.documentElement.scrollTop = 0;
          document.getElementById("sideBar").scrollTop = 0;
        } else {
          this.$message.error("文章内容获取失败");
        }
      });
    },
    markdown(md) {
      let converter = new showdown.Converter();
      return converter.makeHtml(md);
    },
    //获取文章信息
    getBlogData() {
      getBlogData(this.id, (returns) => {
        if (returns.code == "200") {
          this.blogData = returns.data;
          document.title = this.blogData.title + " - " + document.title;
          this.getAuthorData();
          this.$refs.sideBar.pageTag = this.blogData.tag;
          if (getCookie("user") == this.blogData.uid) {
            this.pageSelf = true;
            this.editPath = "/blog/edit/" + this.id;
          } else {
            this.pageSelf = false;
          }
          this.checkCollect();
          this.setShare();
          //访问限制
          switch (this.blogData.permission) {
            case "public":
              this.getContent();
              break;
            case "vcode":
              {
                if (getCookie("user") == this.blogData.uid) {
                  checkLoginState(
                    this.blogData.uid,
                    getCookie("cookie"),
                    (res) => {
                      if (res.code == "200") {
                        this.getContent();
                      } else {
                        this.messageBoxVcode();
                      }
                    }
                  );
                } else {
                  this.messageBoxVcode();
                }
              }
              break;
            case "register":
              {
                //注册用户可见
                checkLoginState(
                  getCookie("user"),
                  getCookie("cookie"),
                  (res) => {
                    if (res.code == "200") {
                      this.getContent();
                    } else {
                      this.messageBoxLogin("没有权限", "请登录后查看", "info");
                    }
                  }
                );
              }
              break;
            case "passwd":
              {
                //需要访问密码
                if (getCookie("user") == this.blogData.uid) {
                  checkLoginState(
                    this.blogData.uid,
                    getCookie("cookie"),
                    (res) => {
                      if (res.code == "200") {
                        this.getContent();
                      } else {
                        this.messageBoxPasswd(
                          "",
                          "请输入访问密码",
                          "info",
                          this.blogData.passwd
                        );
                      }
                    }
                  );
                } else {
                  this.messageBoxPasswd(
                    "",
                    "请输入访问密码",
                    "info",
                    this.blogData.passwd
                  );
                }
              }
              break;
            case "self":
              {
                //仅自己可见
                if (getCookie("user") == this.blogData.uid) {
                  checkLoginState(
                    this.blogData.uid,
                    getCookie("cookie"),
                    (res) => {
                      if (res.code == "200") {
                        this.getContent();
                      } else {
                        this.messageBoxLogin(
                          "没有权限",
                          "本文仅限作者本人查看",
                          "error"
                        );
                      }
                    }
                  );
                } else {
                  this.messageBoxLogin(
                    "没有权限",
                    "本文仅限作者本人查看",
                    "error"
                  );
                }
              }
              break;
            default:
              this.getContent();
              break;
          }
        } else {
          window.location = window.location + "/error";
        }
      });
    },
    //获取作者信息
    getAuthorData() {
      getUserData(this.blogData.uid, (returns) => {
        this.user = returns.data;
      });
    },
    //弹窗（登录）
    messageBoxLogin(title, msg, type) {
      this.$confirm(msg, title, {
        confirmButtonText: "登录",
        modal: false,
        showCancelButton: false,
        showClose: false,
        closeOnClickModal: false,
        closeOnHashChange: false,
        customClass: this.theme.blur ? "blur" : null,
        type: type,
      }).then(() => {
        this.$emit("login", false);
      });
    },
    //弹窗（密码）
    messageBoxPasswd(title, msg, type, veri) {
      this.$confirm(msg, title, {
        confirmButtonText: "验证",
        modal: false,
        showCancelButton: false,
        showClose: false,
        closeOnClickModal: false,
        closeOnHashChange: false,
        dangerouslyUseHTMLString: true,
        showInput: true,
        customClass: this.theme.blur ? "blur" : null,
        type: type,
        beforeClose: (act, ins, done) => {
          ins.confirmButtonLoading = true;
          ins.confirmButtonText = "验证中…";
          setTimeout(() => {
            if (veri == sha256(ins.inputValue, 1)) {
              done();
            } else {
              this.$message.error("访问密码错误");
              ins.confirmButtonLoading = false;
              ins.confirmButtonText = "验证";
            }
          }, 1500);
        },
      }).then(() => {
        this.getContent();
      });
    },
    //弹窗（验证码）
    messageBoxVcode() {
      this.vcodeDialog = true;
    },
    //验证验证码
    verifyVcode() {
      let result = this.$refs.vcode.verifyVcode(this.vcodeInput);
      if (result == true) {
        this.getContent();
        this.vcodeDialog = false;
      } else {
        this.$message.error("验证码错误");
      }
    },
    //删除文章
    delPage() {
      if (this.id == this.delnoid) {
        delPage(getCookie("user"), getCookie("cookie"), this.id, (res) => {
          if (res.code == "200") {
            this.$message.success("删除成功");
            setTimeout(() => {
              window.location = "/blog";
            }, 2000);
          } else if (res.code == "204") {
            this.$message.error("您没有权限删除这篇文章");
          } else {
            this.$message.error("文章删除失败");
          }
        });
      } else {
        this.$message.error("noid输入不正确");
      }
    },
    //检查是否收藏
    checkCollect() {
      if (getCookie("user")) {
        checkCollect(getCookie("user"), this.id, (res) => {
          if (res.code == "200") {
            this.collect = res.data;
          }
        });
      }
    },
    //收藏&取消收藏文章
    pageCollect() {
      pageCollect(
        getCookie("user"),
        getCookie("cookie"),
        this.id,
        this.collect,
        (res) => {
          if (res.code == "200") {
            this.collect = !this.collect;
          } else if (res.code == "204") {
            this.$message.error("你没有权限进行这个操作，请检查你的账号状态");
          } else {
            this.$message.error("操作失败");
          }
        }
      );
    },
    //分享功能
    setShare() {
      this.url = window.location;
      this.share.qq =
        "https://connect.qq.com/widget/shareqq/index.html?url=" +
        this.url +
        "&desc=" +
        this.blogData.title;
      this.share.qzone =
        "https://sns.qzone.qq.com/cgi-bin/qzshare/cgi_qzshare_onekey?to=qzone&url=" +
        this.url +
        "&title=" +
        this.blogData.title +
        "&summary=";
      this.share.wechat = "https://www.qq.com";
      this.share.weibo =
        "http://service.weibo.com/share/share.php?url=" +
        this.url +
        "&sharesource=weibo&title=" +
        this.blogData.title +
        "&pic=" +
        this.blogData.img;
      this.share.twitter =
        "https://twitter.com/share?text=" +
        this.blogData.title +
        "&url=" +
        this.url;
      this.share.facebook =
        "https://www.facebook.com/sharer.php?title=" +
        this.blogData.title +
        "&u=" +
        this.url;
      this.share.linkedin =
        "https://www.linkedin.com/shareArticle?mini=true&url=" +
        this.url +
        "&title=" +
        this.blogData.title +
        "&summary=" +
        this.blogData.subtitle +
        "&source=LinkedIn";
      this.share.skype =
        "https://web.skype.com/share?url=" +
        this.url +
        "&lang=zh-cn&flow_id=c3e7704d-845d-4084-a7e5-24a25353cc25&source=msn";
    },
    //复制
    copyText(value) {
      navigator.clipboard.writeText(value);
      this.$message.success("复制成功");
    },
  },
};
</script>
<style scoped>
#blog /deep/ .el-container {
  max-width: 1100px;
  margin: 0 auto;
}
.pagePanel {
  margin: 20px 12px 20px 12px;
  padding: 30px;
  border-radius: 6px;
  box-shadow: 0 0 2px rgba(0, 0, 0, 0.2);
  overflow: hidden;
  background-color: rgba(255, 255, 255, 0.95);
  position: relative;
}

.pageText >>> img {
  max-width: 600px;
  width: calc(100% - 40px);
  margin: 20px auto;
  display: block;
  box-shadow: 0 0 20px rgba(0, 0, 0, 0.2);
}

.pageText >>> .author {
  text-align: right;
  font-weight: bold;
}

.pageText >>> .cc {
  text-align: right;
  font-style: italic;
}
</style>