import conf from "@/config.json"
var server = conf.server + 'post'

function ajax(data, cellback) {
    let request = new XMLHttpRequest()
    request.open("post", server, true)
    request.send(JSON.stringify(data))
    request.onload = () => {
        let returns = JSON.parse(request.responseText)
        cellback(returns)
    }
}

//获取搜索栏placeholder
export function getExcerpt(cellback) {
    let send = {
        "command": "getExcerpt",
    }
    ajax(send, cellback)
}

