<template>
  <div
    id="contentPanel"
    :style="{
      backgroundImage: theme.background
        ? 'url(' + theme.backgroundImg + ')'
        : null,
    }"
  >
    <top-bar
      pageTitle="Qisato"
      :style="{ opacity: view }"
      style="transition: opacity 100ms ease"
      :user="user"
      :theme="theme"
      :login="login"
      ref="topBar"
      @drawerAppear="
        if (drawer == true) {
          drawer = false;
        } else {
          drawer = true;
        }
      "
      @viewThemeWindow="theme.dialog = true"
      @login="loginDialog = true"
    />
    <router-view
      :style="{ opacity: view }"
      style="transition: opacity 100ms ease"
      :user="user"
      :theme="theme"
      :login="login"
      @login="
        loginDialog = true;
        loginDialogCloseButton = $event;
      "
    />
    <el-drawer
      :visible.sync="drawer"
      :direction="direction"
      :size="330"
      :modal="false"
      :custom-class="'drawer ' + (theme.blur ? 'blur' : null)"
    >
      <drawer-list />
    </el-drawer>
    <el-dialog
      title="个性化"
      :modal="false"
      :visible.sync="theme.dialog"
      width="500px"
      :append-to-body="true"
      top="140px"
      :custom-class="theme.blur ? 'blur' : null"
      style="user-select: none"
    >
      <div
        v-show="this.theme.tip"
        style="position: absolute; top: 55px; right: 65px"
      >
        注意：过亮的主题颜色将对显示效果产生影响
      </div>
      <div style="text-align: center">
        <div style="display: inline-block">
          <table
            style="
              width: 320px;
              height: 40px;
              margin-right: 20px;
              box-shadow: 0 0 4px rgba(0, 0, 0, 0.2);
              cursor: pointer;
            "
            cellpadding="0"
            cellspacing="0"
          >
            <tr>
              <td
                v-for="color in theme.select"
                :key="color"
                :style="{ backgroundColor: color }"
                @click="selectColor(color)"
              ></td>
            </tr>
          </table>
        </div>
        <el-color-picker
          v-model="theme.color"
          @change="themeColorToCookie(theme.color)"
        ></el-color-picker>
      </div>
      <div style="padding: 20px; text-align: center">
        背景
        <el-switch
          v-model="theme.background"
          active-color="#13ce66"
          @change="themeBackgroundChange(theme.background)"
        >
        </el-switch>
        &nbsp;&nbsp; 模糊效果
        <el-switch
          v-model="theme.blur"
          active-color="#13ce66"
          @change="themeBlurChange(theme.blur)"
        >
        </el-switch>
      </div>
    </el-dialog>
    <el-dialog
      :visible.sync="loginDialog"
      :show-close="loginDialogCloseButton"
      :modal="false"
      width="500px"
      :append-to-body="true"
      top="30vh"
      class="blur"
      :custom-class="theme.blur ? 'blur' : null"
      style="background-color: #0000 !important"
      :close-on-click-modal="false"
      :close-on-press-escape="loginDialogCloseButton"
    >
      <login />
    </el-dialog>
    <el-backtop target="" :right="30" :bottom="30">
      <div
        style="
          height: 100%;
          width: 100%;
          background-color: #f2f5f680;
          box-shadow: 0 0 6px rgba(0, 0, 0, 0.12);
          text-align: center;
          line-height: 40px;
        "
        :style="{ color: theme.color }"
        class="blur"
      >
        <i class="fas fa-arrow-up"></i>
      </div>
    </el-backtop>
  </div>
</template>

<script>
import topBar from "./components/topBar.vue"; //顶栏
import drawerList from "./components/drawerList.vue"; //侧边栏
import login from "./components/login.vue"; //登录
import { getUserData, getBackgroundImg } from "@/api/ajax.js";
import { getCookie, writeCookie } from "@/api/function.js";

export default {
  name: "contentPanel",
  components: {
    topBar,
    drawerList,
    login,
  },
  data: function () {
    return {
      view: 0,
      drawer: false,
      direction: "ltr",
      user: {},
      theme: {
        dialog: false,
        select: [
          "#F4511E",
          "#FFB300",
          "#FFEB3B",
          "#8BC34A",
          "#43A047",
          "#00BCD4",
          "#2196F3",
          "#9C27B0",
        ],
        background: false,
        backgroundImg: null,
        blur: false,
        color: "#2196f3",
        tip: false,
      },
      loginDialog: false,
      loginDialogCloseButton: true,
      login: false,
    };
  },
  created() {
    this.getTheme();
    this.getBackground();
    this.getUser();
    setTimeout(() => {
      this.view = 1;
    }, 200);
  },
  methods: {
    //获取壁纸
    getBackground() {
      getBackgroundImg((respond) => {
        this.theme.backgroundImg = respond.data;
      });
    },
    //读取Cookie中主题信息
    getTheme() {
      getCookie("themeColor")
        ? (this.theme.color = getCookie("themeColor"))
        : null;
      getCookie("themeBackgroundSwitch")
        ? (this.theme.background = JSON.parse(
            getCookie("themeBackgroundSwitch")
          ))
        : null;
      getCookie("themeBlurSwitch")
        ? (this.theme.blur = JSON.parse(getCookie("themeBlurSwitch")))
        : null;
    },
    //选择主题颜色
    selectColor(color) {
      this.theme.color = color;
      this.themeColorToCookie(color);
    },
    //主题颜色写入Cookie
    themeColorToCookie(color) {
      if (color == null) {
        this.theme.color = "#2196F3";
        color = "#2196F3";
      }
      this.themeColorLight(color);
      writeCookie("themeColor", color);
    },
    //主题颜色明暗度
    themeColorLight(color) {
      console.log(color);
      let r = Number("0x" + color.slice(1, 3));
      let g = Number("0x" + color.slice(3, 5));
      let b = Number("0x" + color.slice(5));
      let max = Math.max(r, g, b);
      let min = Math.min(r, g, b);
      let light = (min + max) / 2;
      if (light > 200) {
        this.theme.tip = true;
      } else {
        this.theme.tip = false;
      }
    },
    //背景图片开关
    themeBackgroundChange(state) {
      writeCookie("themeBackgroundSwitch", state);
    },
    //模糊效果开关
    themeBlurChange(state) {
      writeCookie("themeBlurSwitch", state);
    },
    //获取已登录用户信息
    getUser() {
      let user = getCookie("user");
      console.log(user);
      if (user) {
        getUserData(user, (returns) => {
          this.user = returns.data;
          this.login = true;
          //用户状态提示
          switch (this.user.status) {
            case 0:
              this.$notify({
                title: "此账号没有生效",
                message: "请联系管理员获取详细信息",
                type: "error",
              });
              break;
            case 1:
              break;
            case 2:
              this.$notify({
                title: "你的账号没有激活",
                message:
                  "账号在没有激活的情况下发布、评论等功能将受到限制。请您尽快答题激活您的账号。<a href='/register/activation'><i class='fas fa-bolt'></i> 激活账号</a>",
                type: "info",
                dangerouslyUseHTMLString: true,
              });
              break;
            case 3:
              this.$notify({
                title: "此账号已被冻结",
                message: "请联系管理员获取详细信息",
                type: "warning",
              });
              break;
            case 4:
              this.$notify({
                title: "账号封禁中",
                message:
                  "此账号因违反相关规定已被封禁，请浏览小黑屋查看详细信息",
                type: "error",
              });
              break;
            case 5:
              this.$notify({
                title: "此账号已注销",
                message: "请联系管理员获取详细信息",
                type: "error",
              });
              break;
            default:
              this.$notify({
                title: "账号状态异常",
                message: "请联系管理员获取详细信息",
                type: "error",
              });
              break;
          }
        });
      }
    },
  },
};
</script>

<style scoped>
#contentPanel {
  color: #37474f;
  font-size: 14px;
  background: #fafafa no-repeat fixed center;
  background-size: cover;
  min-height: 100vh;
  min-width: 500px;
}
</style>

<style>
a {
  color: inherit;
  text-decoration: inherit;
}
.el-input > input {
  background-color: rgba(255, 255, 255, 0.9);
  border-radius: 6px;
}
.el-drawer__wrapper {
  z-index: 1500 !important;
}
.el-drawer__body {
  scrollbar-width: none;
}
.el-drawer__body::-webkit-scrollbar {
  width: 0;
}
.drawer {
  padding-top: 20px;
}
.el-drawer__close-btn {
  position: relative;
  top: 55px;
}
.blur {
  backdrop-filter: blur(24px);
  background-color: rgba(255, 255, 255, 0.88) !important;
}
.unblur {
  background-color: #ffffff !important;
}
.el-popover {
  color: #37474f !important;
}
.el-message {
  z-index: 5100 !important;
  background-color: #edf2fccc !important;
  border-color: #ebeef5dd !important;
  backdrop-filter: blur(24px);
}
.el-message--success {
  background-color: #f0f9ebcc !important;
  border-color: #e1f3d8dd !important;
  backdrop-filter: blur(24px);
}
.el-message--warning {
  background-color: #fdf6eccc !important;
  border-color: #faecd8dd !important;
  backdrop-filter: blur(24px);
}
.el-message--error {
  background-color: #fef0f0cc !important;
  border-color: #fde2e2dd !important;
  backdrop-filter: blur(24px);
}
.el-message-box__wrapper {
  backdrop-filter: blur(24px);
}

/* 滚动条 */
::-webkit-scrollbar {
  width: 10px;
  height: 10px;
}

::-webkit-scrollbar-track {
  border-radius: 5px;
  background: rgba(0, 0, 0, 0.06);
  box-shadow: inset 0 0 5px rgba(0, 0, 0, 0.08);
}
::-webkit-scrollbar-thumb {
  border-radius: 5px;
  background: #c9c9c9;
  box-shadow: inset 0 0 5px rgba(0, 0, 0, 0.08);
}
* {
  scrollbar-width: thin;
  transition: color 100ms ease;
}
*::selection {
  background-color: #00b7ff3f;
}
</style>
