          <div style="height: 160px; width: 100%; overflow: hidden">
            <div
              class="bgi"
              :style="{ backgroundImage: 'url(' + theme.backgroundImg + ')' }"
            ></div>
          </div>
          <div class="userData">
            <img
              :src="user.avatar || require('@/img/login.svg')"
              style="
                width: 160px;
                height: 160px;
                margin: 8px;
                border: rgba(200, 200, 200, 0.25) 4px solid;
                border-radius: 160px;
                box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
                background-color: rgba(0, 0, 0, 0.1);
                position: absolute;
                top: -110px;
                left: 20px;
              "
            />
            <div
              style="
                position: absolute;
                top: -60px;
                left: 225px;
                font-size: 36px;
                color: #fff;
                text-shadow: 0 0 10px rgba(0, 0, 0, 0.3);
                overflow: hidden;
                width: calc(100% - 335px);
                text-overflow: ellipsis;
                overflow: hidden;
                white-space: nowrap;
