            >
              {{ user.name || "User" }}
            </div>
            <div
              style="
                position: absolute;
                top: 8px;
                left: 225px;
                font-size: 16px;
                overflow: hidden;
                width: calc(100% - 335px);
                text-overflow: ellipsis;
                overflow: hidden;
                white-space: nowrap;
              "
            >
              {{ user.signature || "Signature" }}
            </div>
            <div
              style="
                position: absolute;
                top: 34px;
                left: 225px;
                font-size: 16px;
                overflow: hidden;
                width: calc(100% - 335px);
                text-overflow: ellipsis;
                overflow: hidden;
                white-space: nowrap;
                font-weight: bold;
              "
            >
              <span>
                <i class="fas fa-user"></i>
                {{ getRoleName(user.role) }}
              </span>
              <span> </span>
            </div>
            <div style="padding: 80px 30px 30px 30px">
              <el-tabs v-model="userTab">
                <el-tab-pane
                  :label="
                    '文章 ' +
                    (blogLists.length > 0 ? ' ' + blogLists.length : '')
                  "
                  name="0"
                >
                  <div style="padding: 10px 10px 0 10px">
                    <div
                      v-if="blogLists.length == 0"
                      style="text-align: center; color: #636363"
                    >
                      <i>还没有发布任何文章</i>
                    </div>
                    <blog-column
                      v-for="column in blogLists"
                      :key="column.noid"
                      :column="column"
                      :theme="theme"
                    />
                  </div>
                </el-tab-pane>
                <el-tab-pane
                  :label="
                    '收藏' +
                    (collectList.length > 0 ? ' ' + collectList.length : '')
                  "
                  name="1"
                >
                  <div style="padding: 10px 10px 0 10px">
                    <div
                      v-if="collectList.length == 0"
                      style="text-align: center; color: #636363"
                    >
                      <i>还没有收藏任何文章</i>
                    </div>
                    <blog-column
                      v-for="column in collectList"
                      :key="column.noid"
                      :column="column"
                      :theme="theme"
                    />
                  </div>
                </el-tab-pane>
                <el-tab-pane label="关注" name="2">
                  <div style="padding: 10px 10px 0 10px">
                    <div v-if="1" style="text-align: center; color: #636363">
                      <i>还没有关注任何人</i>
                    </div>
                  </div>
                </el-tab-pane>
                <el-tab-pane label="个人资料" name="3">
                  <div style="padding: 10px 10px 0 10px">
                    <div style="display: flex">
                      <div style="flex: 3; line-height: 38px">
                        <div v-if="myself">
                          <table
                            style="width: 100%"
                            cellpadding="0"
                            cellspacing="0"
                          >
                            <tr>
                              <td style="width: 100px">昵称：</td>
                              <td>
                                <el-input
                                  v-model="user.name"
                                  size="small"
                                ></el-input>
                              </td>
                            </tr>
                            <tr>
                              <td>个性签名：</td>
                              <td>
                                <el-input
                                  v-model="user.signature"
                                  size="small"
                                ></el-input>
                              </td>
                            </tr>
                            <tr>
                              <td>用户类型：</td>
                              <td style="padding-left: 14px">
                                {{ getRoleName(user.role) }}
                              </td>
                            </tr>
                            <tr>
                              <td>注册日期：</td>
                              <td style="padding-left: 14px">
                                {{ calculateDate(user.date) }}
                              </td>
                            </tr>
                            <tr>
                              <td style="width: 100px">登录名：</td>
                              <td style="padding-left: 14px">
                                {{ nonpublic.login }}
                              </td>
                            </tr>
                            <tr>
                              <td>UID：</td>
                              <td style="padding-left: 14px">
                                {{ nonpublic.uid }}
                              </td>
                            </tr>
                            <tr>
                              <td>电子邮箱：</td>
                              <td>
                                <el-input :value="nonpublic.email" size="small"
                                  ><el-button
                                    slot="append"
                                    size="small"
                                    @click="dialogModifyMail = true"
                                    >修改</el-button
                                  ></el-input
                                >
                              </td>
                            </tr>
                            <tr>
                              <td>手机：</td>
                              <td>
                                <el-input :value="nonpublic.phone" size="small"
                                  ><el-button
                                    slot="append"
                                    size="small"
                                    @click="dialogModifyPhone = true"
                                    >修改</el-button
                                  ></el-input
                                >
                              </td>
                            </tr>
                          </table>
                          <div style="text-align: right; padding-top: 10px">
                            <el-button
                              size="small"
                              :style="{ backgroundColor: theme.color }"
                              style="color: #fff"
                              @click="dialogModifyPasswd = true"
                            >
                              修改密码
                            </el-button>
                            <el-button
                              size="small"
                              :style="{ backgroundColor: theme.color }"
                              style="color: #fff"
                            >
                              重置登录凭据
                            </el-button>
                          </div>
                        </div>
                        <div v-else style="font-size: 16px; padding: 12px 0">
                          昵称：{{ user.name }}<br />
                          个性签名：{{ user.signature }}<br />
                          用户类型：{{ getRoleName(user.role) }}<br />
                          注册日期：{{ calculateDate(user.date) }}<br />
                        </div>
                      </div>
                      <div style="flex: 2; text-align: center">
                        <div>
                          <img
                            :src="avatarImgUrl || require('@/img/login.svg')"
                            style="
                              width: 160px;
                              height: 160px;
                              margin: 8px;
                              border: rgba(200, 200, 200, 0.25) 4px solid;
                              border-radius: 160px;
                              box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
                              background-color: rgba(0, 0, 0, 0.1);
                            "
                          />
                        </div>
                        <div style="margin: 10px 0" v-if="myself">
                          <el-popover
                            placement="bottom"
                            trigger="click"
                            :popper-class="theme.blur ? 'blur' : null"
                          >
                            <el-button
                              slot="reference"
                              :style="{ backgroundColor: theme.color }"
                              style="color: #fff"
                            >
                              修改头像
                            </el-button>
                            <div>
                              <el-popover
                                trigger="manual"
                                v-model="avatarImg"
                                :popper-class="theme.blur ? 'blur' : null"
                                @show="selectPopover(0)"
                                @hide="selectPopover(1)"
                                ><div slot="reference">
                                  图片地址
                                  <el-input
                                    size="small"
                                    v-model="avatarImgUrl"
                                    style="width: 300px; margin: 0 10px 0 5px"
                                    :clearable="true"
                                  ></el-input>
                                  <el-button
                                    size="small"
                                    @click="avatarImg = !avatarImg"
                                    type="primary"
                                    >上传图片</el-button
                                  >
                                </div>
                                <div style="height: 500px; width: 600px">
                                  <span
                                    @click="avatarImg = false"
                                    style="
                                      position: absolute;
                                      top: 4px;
                                      right: 4px;
                                      padding: 0 8px;
                                      font-size: 20px;
                                      cursor: pointer;
                                      z-index: 100;
                                    "
                                    >×</span
                                  >
                                  <upload-img
                                    :theme="theme"
                                    :md="false"
                                    :check="true"
                                    ref="avatarImg"
                                    @selectImg="avatarImgUrl = $event"
                                  />
                                </div>
                              </el-popover>
                            </div>
                          </el-popover>
                        </div>
                      </div>
                    </div>
                    <div style="text-align: right; padding: 10px 0">
                      <el-button
                        :style="{ backgroundColor: theme.color }"
                        style="color: #fff"
                        @click="modifyUserData"
                      >
                        保存所有更改
                      </el-button>
                    </div>
                  </div>
                </el-tab-pane>
              </el-tabs>
            </div>
          </div>
        </div>
      </el-main>
      <el-aside class="hidden-xs-only" width="274px">
        <side-bar
          :user="user"
          :theme="theme"
          :menu="menuSelf ? menuA : menuB"
          :login="login"
          :starButton="!menuSelf"
          ref="sideBar"
        />
      </el-aside>
    </el-container>
    <el-dialog
      top="20vh"
      width="500px"
      :modal="false"
      title="修改电子邮箱"
      :visible.sync="dialogModifyMail"
      :append-to-body="true"
      :custom-class="theme.blur ? 'blur' : null"
      class="blur"
      style="background-color: #0000 !important"
      @closed="clearDialogInput"
    >
      <table
        style="width: 100%; line-height: 46px"
        cellpadding="0"
        cellspacing="0"
      >
        <tr>
          <td style="width: 140px">请输入验证码：</td>
          <td>
            <el-input size="medium" v-model="vcodeOld">
              <el-button
                slot="append"
                size="small"
                @click="sendVcode('mail', 'old')"
                >发送验证码</el-button
              ></el-input
            >
          </td>
        </tr>
        <tr>
          <td>请输入新的电子邮箱：</td>
          <td>
            <el-input
              @blur="checkMail"
              size="medium"
              v-model="newInput"
            ></el-input>
          </td>
        </tr>
        <tr>
          <td style="width: 140px">验证新的电子邮箱：</td>
          <td>
            <el-input size="medium" v-model="vcodeNew">
              <el-button
                slot="append"
                size="small"
                @click="sendVcode('mail', 'new')"
                >发送验证码</el-button
              ></el-input
            >
          </td>
        </tr>
      </table>
      <div style="text-align: right"><span>我的原电子邮箱已不再使用</span></div>
      <div style="text-align: center; margin-top: 10px">
        <el-button type="danger" @click="clearDialogInput">取消</el-button>
        <el-button type="primary" @click="updateMail">确定</el-button>
      </div>
    </el-dialog>
    <el-dialog
      top="20vh"
      width="500px"
      :modal="false"
      title="修改手机号"
      :visible.sync="dialogModifyPhone"
      :append-to-body="true"
      :custom-class="theme.blur ? 'blur' : null"
      class="blur"
      style="background-color: #0000 !important"
      @closed="clearDialogInput"
    >
      <table
        style="width: 100%; line-height: 46px"
        cellpadding="0"
        cellspacing="0"
      >
        <tr>
          <td style="width: 140px">请输入验证码：</td>
          <td>
            <el-input size="medium" v-model="vcodeOld">
              <el-button
                slot="append"
                size="small"
                @click="sendVcode('phone', 'old')"
                >发送验证码</el-button
              ></el-input
            >
          </td>
        </tr>
        <tr>
          <td>请输入新的手机号：</td>
          <td><el-input size="medium" v-model="newInput"></el-input></td>
        </tr>
        <tr>
          <td style="width: 140px">验证新的手机号：</td>
          <td>
            <el-input size="medium" v-model="vcodeNew">
              <el-button
                slot="append"
                size="small"
                @click="sendVcode('phone', 'new')"
                >发送验证码</el-button
              ></el-input
            >
          </td>
        </tr>
      </table>
      <div style="text-align: right"><span>我的原手机号已不再使用</span></div>
      <div style="text-align: center; margin-top: 10px">
        <el-button type="danger" @click="clearDialogInput">取消</el-button>
        <el-button type="primary">确定</el-button>
      </div>
    </el-dialog>
    <el-dialog
      top="20vh"
      width="500px"
      :modal="false"
      title="修改密码"
      :visible.sync="dialogModifyPasswd"
      :append-to-body="true"
      :custom-class="theme.blur ? 'blur' : null"
      class="blur"
      style="background-color: #0000 !important"
      @closed="clearDialogInput"
    >
      <table
        style="width: 100%; line-height: 46px"
        cellpadding="0"
        cellspacing="0"
      >
        <tr>
          <td style="width: 140px">请输入原密码：</td>
          <td>
            <el-input
              size="medium"
              v-model="oldPasswd"
              show-password
            ></el-input>
          </td>
        </tr>
        <tr>
          <td>请输入新密码：</td>
          <td>
            <el-input
              size="medium"
              v-model="newPasswd"
              show-password
            ></el-input>
          </td>
        </tr>
        <tr>
          <td>请再次输入新密码：</td>
          <td>
            <el-input
              size="medium"
              v-model="newPasswdNext"
              show-password
            ></el-input>
          </td>
        </tr>
      </table>
      <div style="text-align: right"><span>我忘记了我的密码</span></div>
      <div style="text-align: center; margin-top: 10px">
        <el-button type="danger" @click="clearDialogInput">取消</el-button>
        <el-button type="primary" @click="updatePasswd">确定</el-button>
      </div>
    </el-dialog>
  </div>
</template>
<script>
import sideBar from "./components/sideBar.vue";
import uploadImg from "./components/upload.vue";
import blogColumn from "./components/blogColumn.vue";
import { getCookie, sha256 } from "@/api/function.js";
import {
  getUserData,
  getBlogList,
  getCollect,
  getUserLogin,
  modifyUserData,
  modifyUserMoPOldVcodeSend,
  modifyUserMoPNewVcodeSend,
  checkRegUserMail,
  updateUserMail,
  updateUserPhone,
  updateUserPasswd,
} from "@/api/ajax.js";
export default {
  uid: null,
  name: "user",
  components: {
    blogColumn,
    sideBar,
    uploadImg,
  },
  data: () => {
    return {
      loading: false,
      user: {},
      myself: false,
      nonpublic: {},
      menuSelf: false,
      userTab: "0",
      blogLists: [],
      collectList: [],
      avatarImg: false,
      avatarImgUrl: null,
      dialogModifyMail: false,
      dialogModifyPhone: false,
      dialogModifyPasswd: false,
      vcodeOld: null,
      vcodeNew: null,
      newInput: null,
      oldPasswd: null,
      newPasswd: null,
      newPasswdNext: null,
      menuA: {
        userActionMenuPanel: [
          //建议：分两组，每组两个
          {
            group: "0",
            list: [
              {
                title: "写文章",
                path: "/blog/edit",
                icon: "fas fa-edit",
              },
              {
                title: "传照片",
                path: "",
                icon: "fas fa-image",
              },
            ],
          },
          {
            group: "1",
            list: [
              {
                title: "个人主页",
                path: "/user/my",
                icon: "fas fa-user",
              },
              {
                title: "创作中心",
                path: "",
                icon: "fas fa-paper-plane",
              },
            ],
          },
        ],
        userActionMenuList: [
          {
            title: "我的收藏",
            path: "",
            icon: "fas fa-bookmark fa-fw",
          },
          {
            title: "我的关注",
            path: "",
            icon: "fas fa-star fa-fw",
          },
          {
            title: "我的相册",
            path: "",
            icon: "fas fa-images fa-fw",
          },
          {
            title: "个人资料",
            path: "",
            icon: "fas fa-child fa-fw",
          },
        ],
      },
      menuB: {
        userActionMenuPanel: [
          //建议：分两组，每组两个
          {
            group: "0",
            list: [
              {
                title: "ta的文章",
                path: "",
                icon: "fas fa-file-alt",
              },
              {
                title: "ta的照片",
                path: "",
                icon: "fas fa-images",
              },
            ],
          },
          {
            group: "1",
            list: [
              {
                title: "ta的主页",
                path: "",
                icon: "fas fa-user",
              },
              {
                title: "创作中心",
                path: "",
                icon: "fas fa-paper-plane",
              },
            ],
          },
        ],
        userActionMenuList: [
          {
            title: "ta的收藏",
            path: "",
            icon: "fas fa-bookmark fa-fw",
          },
          {
            title: "ta的关注",
            path: "",
            icon: "fas fa-star fa-fw",
          },
          {
            title: "ta的资料",
            path: "",
            icon: "fas fa-child fa-fw",
          },
        ],
      },
    };
  },
  props: ["id", "theme", "login"],
  mounted() {
    if (this.id == "my") {
      this.uid = getCookie("user");
    } else {
      this.uid = this.id;
    }
    this.getUser();
    this.getBlog();
    this.getCollect();
    if (this.uid == getCookie("user")) {
      this.myself = true;
      this.getUserNonpublic();
    }
  },
  methods: {
    getUser() {
      getUserData(this.uid, (returns) => {
        if (returns.code == "200") {
          this.user = returns.data;
          this.avatarImgUrl = this.user.avatar;
          document.title = this.user.name + "的用户信息";
          if (getCookie("user") == this.uid) {
            this.menuSelf = true;
          } else {
            this.menuSelf = false;
          }
        } else {
          window.location = window.location + "/error";
        }
      });
    },
    //获取用户非公开信息
    getUserNonpublic() {
      getUserLogin(this.uid, (ret) => {
        if (ret.code == "200") {
          this.nonpublic = ret.data;
        }
      });
    },
    getRoleName(r) {
      switch (r) {
        case 1:
          return "站务";
        case 2:
          return "站务";
        case 3:
          return "管理员";
        case 4:
          return "普通用户";
        case 5:
          return "测试用户";
        default:
          return "No Type ";
      }
    },
    //获取用户文章
    getBlog() {
      getBlogList(null, this.uid, (returns) => {
        this.blogLists = returns.data.reverse();
        this.loading = false;
        document.documentElement.scrollTop = 0;
      });
    },
    //获取用户收藏
    getCollect() {
      getCollect(this.uid, (res) => {
        if (res.code == "200") {
          this.collectList = res.data.reverse();
        } else {
          setTimeout(() => {
            this.$message.error("用户收藏获取失败");
          }, 2000);
        }
      });
    },
    //计算日期
    calculateDate(value) {
      let date = new Date();
      let y, m, d;
      date.setTime(value);
      y = date.getFullYear();
      m = date.getMonth() + 1;
      d = date.getDate();
      return y + "-" + m + "-" + d;
    },
    //图片选择窗口
    selectPopover(v) {
      if (v == 0) {
        this.$refs.avatarImg.getImg();
      } else if (v == 1) {
        setTimeout(() => {
          this.$refs.avatarImg.uploadPageImgClearFiles();
          this.$refs.avatarImg.selectImgAction = "first";
        }, 500);
      }
    },
    //修改用户信息
    modifyUserData() {
      let send = {
        name: this.user.name,
        signature: this.user.signature,
      };
      modifyUserData(getCookie("user"), getCookie("cookie"), send, (ret) => {
        if (ret.code == "200") {
          this.$message.success("用户信息修改成功");
          setTimeout(() => {
            location.reload();
          }, 2000);
        } else if (ret.code == "204") {
          this.$message.error("你没有权力进行这个操作");
        } else {
          this.$message.error("操作失败");
        }
      });
    },
    //关闭窗口清除输入
    clearDialogInput() {
      this.dialogModifyMail = false;
      this.dialogModifyPhone = false;
      this.dialogModifyPasswd = false;
      setTimeout(() => {
        this.vcodeOld = null;
        this.vcodeNew = null;
        this.newInput = null;
        this.oldPasswd = null;
        this.newPasswd = null;
        this.newPasswdNext = null;
      }, 200);
    },
    //发送验证码
    sendVcode(type, oldOrNew) {
      if (oldOrNew == "old") {
        modifyUserMoPOldVcodeSend(this.user.uid, type, (ret) => {
          if (ret.code == "200") {
            this.$message.success("验证码已发送");
          } else if (ret.code == "204") {
            this.$message.warning("请在" + ret.data + "秒后重试");
          } else {
            this.$message.error("验证码发送失败");
          }
        });
      } else if (oldOrNew == "new") {
        let mail = this.newInput;
        modifyUserMoPNewVcodeSend(mail, type, (ret) => {
          if (ret.code == "200") {
            this.$message.success("验证码已发送");
          } else if (ret.code == "202") {
            let msg = "登录凭据";
            if (type == "mail") {
              msg = "电子邮箱";
            } else if (msg == "phone") {
              msg = "手机号";
            }
            this.$message.warning("该" + msg + "已被占用");
          } else if (ret.code == "204") {
            this.$message.warning("请在" + ret.data + "秒后重试");
          } else {
            this.$message.error("验证码发送失败");
          }
        });
      }
    },
    //检查邮箱
    checkMail() {
      let mail = this.newInput;
      let verify = /^\w+([-+.]\w+)*@\w+([-.]\w+)*\.\w+([-.]\w+)*$/g;
      if (mail) {
        if (verify.test(mail) == true) {
          checkRegUserMail(mail, (res) => {
            if (res.code == "200") {
              true;
            } else {
              this.$message.warning("该电子邮箱已被占用");
            }
          });
        } else {
          this.$message.warning("电子邮箱格式不正确");
        }
      }
    },
    //更新邮箱
    updateMail() {
      updateUserMail(
        getCookie("user"),
        getCookie("cookie"),
        this.newInput,
        this.vcodeOld,
        this.vcodeNew,
        (res) => {
          if (res.code == "200") {
            this.$message.success("邮箱修改成功");
            this.nonpublic.email = this.newInput;
            this.dialogModifyMail = false;
            this.clearDialogInput();
          }
        }
      );
    },
    //更新手机号
    updatePhone() {
      updateUserPhone(
        getCookie("user"),
        getCookie("cookie"),
        this.newInput,
        this.vcodeOld,
        this.vcodeNew,
        (res) => {
          if (res.code == "200") {
            this.$message.success("手机号修改成功");
            this.nonpublic.phone = this.newInput;
            this.dialogModifyPhone = false;
            this.clearDialogInput();
          }
        }
      );
    },
    //更新用户密码
    updatePasswd() {
      if (this.newPasswd == this.newPasswdNext) {
        updateUserPasswd(
          getCookie("user"),
          getCookie("cookie"),
          sha256(this.oldPasswd, 16),
          sha256(this.newPasswd, 16),
          (res) => {
            if (res.code == 200) {
              this.$message.success("用户密码修改成功");
              this.dialogModifyPasswd = false;
              this.clearDialogInput();
            } else if (res.code == "201") {
              this.$message.error("密码修改失败");
            } else {
              this.$message.error("密码修改失败，请联系管理员");
            }
          }
        );
      } else {
        this.$message.warning("两次输入密码不一致");
      }
    },
  },
};
</script>
